Debounce ensures a function runs only after it hasn’t been called for a specified delay, preventing rapid-fire executions.

function debounce(fn, delay = 200) {
  let timer;
  return function (...args) {
    const ctx = this;
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(ctx, args), delay);
  };
}

// Example: log the input value 300ms after the user stops typing
// <input id="search" />
const input = document.querySelector('#search');
const onType = (e) => console.log('Searching:', e.target.value);
input.addEventListener('input', debounce(onType, 300));
